client_script:
frappe.web_form.after_load = function () {
    var params = new URLSearchParams(window.location.search);
    var token = params.get('token');
    if (token) {
        frappe.web_form.set_value('location_token', token);
    }
};

frappe.web_form.after_save = function (doc) {
    var code = doc && doc.anonymous_tracking_code;
    if (code) {
        var msg = document.createElement('div');
        msg.style.cssText = 'margin-top:16px;padding:12px 16px;background:#f0fdf4;border:1px solid #86efac;border-radius:6px;font-size:15px;';
        msg.innerHTML = '<strong>Your request has been received.</strong><br>Track it with code: <code style="font-size:16px;letter-spacing:2px;">' + code + '</code>';
        var btn = document.querySelector('.web-form-footer');
        if (btn) btn.parentNode.insertBefore(msg, btn.nextSibling);
    }
};
